const cards=document.querySelector('.cards'),
    out= document.querySelector(".out")
class Tovar_card{
    constructor(title,image,des,price){
        this.price=price,
        this.title=title,
        this.image=image,
        this.des=des
    }
    render(){
        cards.insertAdjacentHTML('afterbegin',`
             <div class="card">
            <img src=${this.image} alt=${this.title} class="card_img">
        </div>
        <h2 class="card_title">${this.title}</h2>
        <p class="card_text">${this.des}</p>
        <p class="price">${this.price}</p>
        <button class="btn">Купить</button>`)
    }
}
fetch("")
    .then((x) => x.json())
    .then((x)=>{return x.map(item=>new Tovar_card(...item))})
    .catch(()=>out.textContent="")

